async (page) => {
  // Dismiss the skill level up dialog
  await page.keyboard.press('Escape');
  await page.waitForTimeout(500);

  // Set up WebSocket monitoring to capture dialogue and quest packets
  await page.evaluate(() => {
    window.__allReceived = [];
    const conn = window.game.socket.connection;
    if (!conn.__patched) {
      conn.__patched = true;
      const orig = conn.onmessage;
      conn.onmessage = function(e) {
        try {
          const d = JSON.parse(e.data);
          if (Array.isArray(d)) {
            d.forEach(item => {
              if (Array.isArray(item) && (item[0] === 31 || item[0] === 23 || item[0] === 45)) {
                window.__allReceived.push(JSON.stringify(item));
              }
            });
          }
        } catch(ex) {}
        if (orig) orig.call(this, e);
      };
    }
  });

  // Use player.follow() to talk to the Forester
  const result = await page.evaluate(() => {
    const entities = window.game.entities.entities;
    let forester = null;
    for (const id in entities) {
      if (entities[id] && entities[id].name === 'Forester') {
        forester = entities[id];
        break;
      }
    }
    if (!forester) return 'Forester not found';
    window.game.input.entity = forester;
    window.game.input.setInteractionTarget();
    window.game.player.follow(forester);
    return `Following Forester instance: ${forester.instance}`;
  });

  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });

  const received = await page.evaluate(() => window.__allReceived);
  return `${result} | Packets: ${JSON.stringify(received)}`;
