async (page) => {
  await page.evaluate(() => {
    window.__allReceived = [];
    const conn = window.game.socket.connection;
    if (!conn.__patched) {
      conn.__patched = true;
      const orig = conn.onmessage;
      conn.onmessage = function(e) {
        try {
          const d = JSON.parse(e.data);
          if (Array.isArray(d)) {
            d.forEach(item => {
              if (Array.isArray(item) && (item[0] === 31 || item[0] === 23 || item[0] === 45)) {
                window.__allReceived.push(item);
              }
            });
          }
        } catch(ex) {}
        if (orig) orig.call(this, e);
      };
    }
  });

  // Talk to Blacksmith
  const result = await page.evaluate(() => {
    const entities = window.game.entities.entities;
    let bs = null;
    for (const id in entities) {
      if (entities[id] && entities[id].name === 'Blacksmith') { bs = entities[id]; break; }
    }
    if (!bs) return 'not found';
    window.game.input.entity = bs;
    window.game.input.setInteractionTarget();
    window.game.player.follow(bs);
    return `talking to ${bs.instance}`;
  });

  await page.waitForTimeout(2000);
  const received = await page.evaluate(() => window.__allReceived.filter(r => r[0] === 31 || r[0] === 23));
  return `${result} | Dialogue: ${JSON.stringify(received)}`;
}

async (page) => {
  await page.keyboard.press('Escape');
  await page.waitForTimeout(300);
  await page.evaluate(() => { window.__allReceived = []; });

  // Use bounding box to click Blacksmith
  const coords = await page.evaluate(() => {
    const entities = window.game.entities.entities;
    let bs = null;
    for (const id in entities) {
      if (entities[id] && entities[id].name === 'Blacksmith') { bs = entities[id]; break; }
    }
    if (!bs) return null;
    const camera = window.game.input.camera;
    const bb = bs.getBoundingBox();
    const zf = camera.zoomFactor;
    return {
      mouseX: Math.round((bb.x + bb.width/2 - camera.x) * zf),
      mouseY: Math.round((bb.y + bb.height/2 - camera.y) * zf),
      instance: bs.instance
    };
  });

  if (!coords) return 'Blacksmith not found';

  await page.evaluate(({x, y}) => {
    document.getElementById('cursor').dispatchEvent(
      new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false })
    );
  }, {x: coords.mouseX, y: coords.mouseY});

  await page.waitForTimeout(2000);
  const received = await page.evaluate(() => window.__allReceived.filter(r => Array.isArray(r) && (r[0] === 31 || r[0] === 23)));

  return `Clicked Blacksmith at (${coords.mouseX}, ${coords.mouseY}) | Dialogue: ${JSON.stringify(received)}`;
}

