async (page) => {
  // Setup WS monitoring
  await page.evaluate(() => {
    window.__villageDialogue = [];
    const conn = window.game.socket.connection;
    conn.__patched = false;
    const orig = conn.onmessage;
    conn.__patched = true;
    conn.onmessage = function(e) {
      try {
        const d = JSON.parse(e.data);
        if (Array.isArray(d)) {
          d.forEach(item => {
            if (Array.isArray(item) && (item[0] === 31 || item[0] === 23)) {
              window.__villageDialogue.push(item);
            }
          });
        }
      } catch(ex) {}
      if (orig) orig.call(this, e);
    };
  });

  // Click Village Girl
  await page.evaluate(({x, y}) => {
